using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // EF Core 9 breaking change: Migrate() now internally uses the execution
        // strategy and runs each migration in a transaction. Manual wrapping with
        // strategy.Execute + BeginTransaction causes nested strategy errors.
        db.Database.Migrate();
    }
}

