using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF Core 9 breaking change: the default discriminator property name
            // changed from "Discriminator" to "$type". Existing documents already
            // store "Discriminator", so we must explicitly preserve the old name.
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
}

using Microsoft.EntityFrameworkCore;

class ProductService
{
    // EF Core 9 breaking change: the Cosmos DB provider no longer supports
    // synchronous I/O. All queries must use async methods.
    // Before (EF Core 8):
    //   var products = db.Products.ToList();
    //   var product = db.Products.First(p => p.Name == name);
    // After (EF Core 9):
    async Task<List<Product>> GetAllAsync(CosmosDbContext db)
    {
        return await db.Products.ToListAsync();
    }

    async Task<Product> GetByNameAsync(CosmosDbContext db, string name)
    {
        return await db.Products.FirstAsync(p => p.Name == name);
    }
}

